#include <iostream>
#include <vector>

using namespace std;

int main()
{
    int vertices = 4;
    vector<vector<int>> matrix(vertices, vector<int>(vertices, 0));

    // Undirected edges: 0-1, 0-2, 1-3
    matrix[0][1] = matrix[1][0] = 1;
    matrix[0][2] = matrix[2][0] = 1;
    matrix[1][3] = matrix[3][1] = 1;

    cout << matrix[0][1] << endl; // edge exists?
    cout << matrix[0][3] << endl; // edge exists?

    return 0;
}

